Javascript.validate:
var val = Services.getValue(AmntPaidDirect.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(AmntPaidDirect.dataBinding, WPU.formatToTwoDP(val));
}
return err;

