function DefaultCurrency610() {}
DefaultCurrency610.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency610.tabIndex = -1;
DefaultCurrency610.maxLength = 1;
DefaultCurrency610.isReadOnly = function(){return true;}
DefaultCurrency610.isTemporary = function(){return true;}
DefaultCurrency610.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency610.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
